# Set sign-in frequency to 4 hours for all apps (users re-auth every 4h)
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Sign-in Frequency - 4h for All Apps'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        ClientAppTypes = @('all')
    }
    SessionControls = @{
        SignInFrequency = @{
            Value = 4
            Type = 'hours'
            IsEnabled = $true
        }
    }
}

# 'Every time' sign-in frequency (no persistent session at all)
# Use for highly sensitive resources like PIM activation portal
$sessionControls = @{
    SignInFrequency = @{
        AuthenticationType = 'primaryAndSecondaryAuthentication'
        FrequencyInterval = 'everyTime'
        IsEnabled = $true
    }
}

# Prevent persistent browser sessions for unmanaged devices
# Prevents 'Stay signed in?' cookie from lasting across browser restarts
$sessionControls = @{
    PersistentBrowser = @{
        Mode = 'never'  # Options: always | never
        IsEnabled = $true
    }
}

# Pattern: managed devices → persistent sessions allowed (less friction)
#          unmanaged devices → never persistent (reduce token exposure)
# Deploy as two separate policies scoped to device compliance state

# App-enforced restrictions for SharePoint and Exchange
# Sends 'isCompliant' or 'isDomainJoined' claims to the app
# SharePoint/Exchange use these claims to allow or restrict features

# Policy: unmanaged devices → limited access to SharePoint (no download)
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: SharePoint Unmanaged - App Enforced Restrictions'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{
            IncludeApplications = @(
                '00000003-0000-0ff1-ce00-000000000000',  # SharePoint Online
                '00000002-0000-0ff1-ce00-000000000000'   # Exchange Online
            )
        }
        Devices = @{
            DeviceFilter = @{
                Mode = 'include'
                Rule = 'device.isCompliant -ne True -and device.trustType -ne "ServerAD"'
            }
        }
    }
    SessionControls = @{
        ApplicationEnforcedRestrictions = @{ IsEnabled = $true }
    }
}

# In SharePoint Admin Center → Policies → Access Control → Unmanaged Devices:
# Set to 'Allow limited, web-only access' to map claim to download restriction

# Conditional Access App Control via Microsoft Defender for Cloud Apps
# Requires: app onboarded to MDCA in Conditional Access App Control mode

# Step 1: In Defender for Cloud Apps portal, go to Settings → Connected Apps
# → Conditional Access App Control apps → select the app → configure

# Step 2: Create CA policy routing session through MDCA proxy
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Salesforce - MDCA Proxy for Unmanaged'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('<salesforce-app-id>') }
        Devices = @{
            DeviceFilter = @{
                Mode = 'include'
                Rule = 'device.isCompliant -ne True'
            }
        }
    }
    SessionControls = @{
        CloudAppSecurity = @{
            CloudAppSecurityType = 'blockDownloads'
            IsEnabled = $true
        }
    }
}

# CloudAppSecurityType options:
# mcasConfigured — use policy set in MDCA portal (most flexible)
# blockDownloads — block all file downloads from the app in this session
# monitorOnly — log all activity without blocking (audit mode)

# Token Protection (Preview) — binds access token to device
# If an attacker steals the token (adversary-in-the-middle), they cannot replay it
# because the token is cryptographically bound to the original device's TPM

# Enable token protection for Teams and Exchange in a CA policy
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Token Protection - Teams + Exchange'
    State = 'enabledForReportingButNotEnforcing'  # start in report-only
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{
            IncludeApplications = @(
                '1fec8e78-bce4-4aaf-ab1b-5451cc387264',  # Teams
                '00000002-0000-0ff1-ce00-000000000000'   # Exchange Online
            )
        }
        ClientAppTypes = @('mobileAppsAndDesktopClients')
    }
    SessionControls = @{
        SecureSignInSession = @{ IsEnabled = $true }
    }
}

# Token protection requires Entra ID P2 and Windows 10/11 with Entra-registered/joined device
# Monitor token binding failures in SigninLogs: TokenProtectionStatus field
